def verify(subject: str, predicate: str, obj: str) -> bool:
    # Define the order of planets from the sun
    planet_order = ['Mercury', 'Venus', 'Earth', 'Mars', 'Jupiter', 'Saturn', 'Uranus', 'Neptune']

    # Find the indices of the subject and object in the planet order
    try:
        subject_index = planet_order.index(subject)
        obj_index = planet_order.index(obj)
    except ValueError:
        # If either subject or object is not in the list, return False
        return False

    # Check if the subject is closer to the sun than the object
    if predicate == 'closer_to_the_sun_than':
        return subject_index < obj_index
    elif predicate == 'farther_from_the_sun_than':
        return subject_index > obj_index
    else:
        # If the predicate is not recognized, return False
        return False
